import{_ as a,o as r,c as t,ag as i}from"./chunks/framework.BqfgOMAh.js";const u=JSON.parse('{"title":"NexusFlow 0.2.0 Beta","description":"","frontmatter":{},"headers":[],"relativePath":"en/releases/0.2.0.md","filePath":"en/releases/0.2.0.md"}'),n={name:"en/releases/0.2.0.md"};function l(o,e,s,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="nexusflow-0-2-0-beta" tabindex="-1">NexusFlow 0.2.0 Beta <a class="header-anchor" href="#nexusflow-0-2-0-beta" aria-label="Permalink to &quot;NexusFlow 0.2.0 Beta&quot;">​</a></h1><p>0.2.0 is the first Beta update after 0.1.0. It expands NexusFlow from a desktop AI Blueprint assistant into an Unreal Engine automation gateway for external IDEs and agents, while improving Blueprint reliability and introducing an experimental Widget Blueprint capability.</p><h2 id="highlights" tabindex="-1">Highlights <a class="header-anchor" href="#highlights" aria-label="Permalink to &quot;Highlights&quot;">​</a></h2><h3 id="embedded-mcp-server" tabindex="-1">Embedded MCP Server <a class="header-anchor" href="#embedded-mcp-server" aria-label="Permalink to &quot;Embedded MCP Server&quot;">​</a></h3><p>The NexusFlow desktop app can now run as an MCP server. MCP-capable IDEs and agents can connect to NexusFlow and use UE context, Skill search, Knowledge loading, Blueprint action execution, node search, template search, and editor commands.</p><h3 id="agent-skill-instructions" tabindex="-1">Agent Skill Instructions <a class="header-anchor" href="#agent-skill-instructions" aria-label="Permalink to &quot;Agent Skill Instructions&quot;">​</a></h3><p>The new <code>nexusflow-skill</code> package provides portable entrypoints for AGENTS, Claude Code, and Cursor, teaching external agents how to use NexusFlow MCP tools safely.</p><h3 id="blueprint-skill-reliability-improvements" tabindex="-1">Blueprint Skill Reliability Improvements <a class="header-anchor" href="#blueprint-skill-reliability-improvements" aria-label="Permalink to &quot;Blueprint Skill Reliability Improvements&quot;">​</a></h3><p>Blueprint read, generation, incremental patching, compile validation, and error recovery workflows have been improved. Handling is more reliable for complex graphs, variables, components, interfaces, dynamic pins, and special nodes.</p><h3 id="widget-skill-mvp" tabindex="-1">Widget Skill MVP <a class="header-anchor" href="#widget-skill-mvp" aria-label="Permalink to &quot;Widget Skill MVP&quot;">​</a></h3><p>The experimental Widget Skill can create and edit UMG Widget Blueprints, including widget tree read/write, property-level patching, branch rewrites, and real preview screenshots.</p><h3 id="agent-friendly-search-workflow" tabindex="-1">Agent-Friendly Search Workflow <a class="header-anchor" href="#agent-friendly-search-workflow" aria-label="Permalink to &quot;Agent-Friendly Search Workflow&quot;">​</a></h3><p>Blueprint template search, template loading, and node search are exposed as MCP tools so agents can discover reusable patterns and correct nodes before building Blueprint logic.</p><h3 id="environment-variable-api-key-references" tabindex="-1">Environment Variable API Key References <a class="header-anchor" href="#environment-variable-api-key-references" aria-label="Permalink to &quot;Environment Variable API Key References&quot;">​</a></h3><p>Model configuration now accepts environment variable references such as <code>${OPENAI_API_KEY}</code> in the API Key field. The real key is resolved by the Tauri backend at runtime, while the app configuration only stores the variable reference.</p><h2 id="upgrade-notes" tabindex="-1">Upgrade Notes <a class="header-anchor" href="#upgrade-notes" aria-label="Permalink to &quot;Upgrade Notes&quot;">​</a></h2><ul><li>If you only use the NexusFlow desktop chat UI, you can upgrade normally.</li><li>If you prefer not to store the real API key in app configuration, enter <code>${ENV_NAME}</code> in the API Key field, for example <code>${OPENAI_API_KEY}</code>.</li><li>If you use Cursor, Claude Code, or custom agents, read <a href="./../guide/mcp">Use NexusFlow from IDEs / Agents</a> and <a href="./../guide/agent-skill">NexusFlow Skill</a>.</li><li>Widget Skill is still experimental; start with small UIs or assets that are easy to roll back.</li></ul>',17)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
